function mergeValue(def: any, raw: any): any {
  if (raw === undefined || raw === null) return def;
  if (Array.isArray(def)) {
    const rawArr = Array.isArray(raw) ? raw : [];
    return def.map((d, i) => mergeValue(d, rawArr[i]));
  }
  if (def && typeof def === 'object') {
    if (typeof raw !== 'object' || Array.isArray(raw)) return def;
    const out: Record<string, any> = {};
    for (const k of Object.keys(def)) out[k] = mergeValue(def[k], raw[k]);
    return out;
  }
  return raw;
}

export const resolveProhibitedContent = (raw: any) => mergeValue(PROHIBITED_DEFAULTS, raw ?? {});
export const resolvePrivacyContent = (raw: any) => mergeValue(PRIVACY_DEFAULTS, raw ?? {});
export const resolveEsignContent = (raw: any) => mergeValue(ESIGN_DEFAULTS, raw ?? {});
export const resolveCardTermsContent = (raw: any) => mergeValue(CARD_TERMS_DEFAULTS, raw ?? {});
